function cleanText(value) {
  return String(value || '')
    .replace(/&/g, 'and')
    .replace(/</g, '')
    .replace(/>/g, '')
    .replace(/_/g, '-')
    .replace(/\*/g, '')
    .replace(/\[/g, '')
    .replace(/\]/g, '')
    .replace(/\(/g, '')
    .replace(/\)/g, '')
    .replace(/`/g, '')
    .replace(/"/g, '')
    .replace(/'/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanUrl(value) {
  return String(value || '')
    .replace(/\s+/g, '')
    .trim();
}

function normalizeUrl(value) {
  return cleanUrl(value).split('?')[0];
}

const aggregated = $json.data || [];
const account = 'YOUR_EMAIL_ACCOUNT';
const maxLength = 3500;

const titleBlacklist = [
  'unsubscribe',
  'privacy',
  'datenschutz',
  'legal',
  'facebook',
  'twitter',
  'instagram',
  'glassdoor',
  'forbes',
  'sign in',
  'login',
  'update your profile',
  'view relevant jobs',
  'manage notifications',
  'preferences',
  'finance',
  'controlling',
  'accounting',
  'sales',
  'marketing',
  'human resources',
  'hr business',
  'procurement',
  'supply chain'
];

const linkBlacklist = [
  'unsubscribe',
  'privacy',
  'datenschutz',
  'legal',
  'facebook',
  'twitter',
  'instagram',
  'glassdoor',
  'forbes',
  'careerhub/me',
  'login'
];

const whitelist = [
  'werkstudent',
  'working student',
  'internship',
  'praktikum',
  'student',
  'engineer',
  'engineering',
  'developer',
  'electronics',
  'elektronik',
  'elektrotechnik',
  'automation',
  'automatisierung',
  'embedded',
  'firmware',
  'software',
  'hardware',
  'systems',
  'systeme',
  'application',
  'testing',
  'validation',
  'python',
  'c++',
  'iot',
  'microcontroller',
  'semiconductor',
  'halbleiter',
  'standard cells',
  'datenanalyse',
  'qualitätsmanagement'
];

function isRelevant(title, link) {
  const t = title.toLowerCase();
  const l = link.toLowerCase();

  if (!title || !link) return false;
  if (!link.startsWith('http')) return false;
  if (title.length < 10) return false;

  if (titleBlacklist.some(b => t.includes(b))) return false;
  if (linkBlacklist.some(b => l.includes(b))) return false;
  if (!whitelist.some(w => t.includes(w))) return false;

  return true;
}

const blocks = [];
const globalSeen = new Set();

for (const email of aggregated) {
  const source = cleanText(email.from?.value?.[0]?.name || 'Unknown');
  const sender = cleanText(email.from?.value?.[0]?.address || '');
  const jobs = email.jobs || [];
  const links = email.links || [];

  const jobLines = [];

  for (let i = 0; i < jobs.length; i++) {
    const title = cleanText(jobs[i]);
    const link = normalizeUrl(links[i]);

    if (!isRelevant(title, link)) continue;

    const key = `${title.toLowerCase()}|${link.toLowerCase()}`;
    if (globalSeen.has(key)) continue;
    globalSeen.add(key);

    jobLines.push(`📌 ${title}\n${link}`);
  }

  if (jobLines.length === 0) continue;

  const block = `━━━━━━━━━━━━━━
🏢 ${source}

${jobLines.join('\n\n')}

📧 ${sender}`;

  blocks.push(block);
}

if (blocks.length === 0) {
  return [];
}

const messages = [];
let current = `📬 ACCOUNT: ${account}\n\n`;

for (const block of blocks) {
  const candidate = current + block + '\n\n';

  if (candidate.length > maxLength) {
    if (current.trim() !== `📬 ACCOUNT: ${account}`) {
      messages.push(current.trim());
    }
    current = `📬 ACCOUNT: ${account}\n\n${block}\n\n`;
  } else {
    current = candidate;
  }
}

if (current.trim().length > 0) {
  messages.push(current.trim());
}

return messages.map((message, index) => ({
  json: {
    message: `Part ${index + 1}/${messages.length}\n\n${message}`
  }
}));

